class Stack:
    def __init__(self):
        self._items = []

    def is_empty(self):
        return not self._items

    def push(self, item):
        self._items.append(item)

    def pop(self):
        if not self.is_empty():
            return self._items.pop()
        else:
            raise IndexError("pop from empty stack")

    def peek(self):
        if not self.is_empty():
            return self._items[-1]
        else:
            raise IndexError("peek from empty stack")

    def size(self):
        return len(self._items)

    def __str__(self):
        return str(self._items)


def _insert_at_bottom(stack, item):
    """
    Helper function to insert an item at the bottom of the stack.
    """
    if stack.is_empty():
        stack.push(item)
    else:
        temp = stack.pop()
        _insert_at_bottom(stack, item)
        stack.push(temp)


def reverse_stack_recursive(stack):
    """
    Reverses a stack using recursion.
    """
    if not stack.is_empty():
        temp = stack.pop()
        reverse_stack_recursive(stack)
        _insert_at_bottom(stack, temp)


if __name__ == "__main__":
    my_stack = Stack()
    my_stack.push(1)
    my_stack.push(2)
    my_stack.push(3)
    my_stack.push(4)

    print("Original Stack:", my_stack)  # Output: Original Stack: [1, 2, 3, 4]

    reverse_stack_recursive(my_stack)

    print("Reversed Stack:", my_stack)  # Output: Reversed Stack: [4, 3, 2, 1]

